        get {
            return userDefaults.bool(forKey: authenticationKey)
        }
        set {
            userDefaults.set(newValue, forKey: authenticationKey)
        }
    }
    
    var isUserAuthenticated: Bool {
        get {
            return userDefaults.bool(forKey: authenticatedKey)
        }
        set {
            userDefaults.set(newValue, forKey: authenticatedKey)
        }
    }
    
    func biometricType() -> BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        if #available(iOS 11.0, *) {
            switch context.biometryType {
            case .none:
                return .none
            case .touchID:
                return .touchID
            case .faceID:
                return .faceID
            @unknown default:
                return .none
            }
        } else {
            return .touchID
        }
    }
    
